#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <signal.h>
#include "../get_next_line.h"

static int	g_test = 1;

static void	sigsegv_handler(int sig)
{
	(void)sig;
	printf("\033[31m[SIGSEGV]\033[0m\n");
	exit(1);
}

static void	title(const char *str)
{
	g_test = 1;
	printf("\033[34m%s\033[0m\n", str);
}

static void	gnl(int fd, const char *expected)
{
	char	*line;
	int		ret;
	int		pass;
	size_t	len;
	char	*stripped;

	line = NULL;
	ret = get_next_line(fd, &line);
	if (expected == NULL)
	{
		pass = (ret == -1) || (ret == 0 && (line == NULL || line[0] == '\0'));
		printf("[%02d] %s (ret=%d)\n", g_test,
			pass ? "\033[32mOK\033[0m" : "\033[31mKO\033[0m", ret);
	}
	else
	{
		len = strlen(expected);
		if (len > 0 && expected[len - 1] == '\n')
		{
			stripped = malloc(len);
			if (!stripped)
				return ;
			memcpy(stripped, expected, len - 1);
			stripped[len - 1] = '\0';
			pass = (ret == 1 && line != NULL && strcmp(line, stripped) == 0);
			free(stripped);
		}
		else
		{
			pass = (ret == 0 && line != NULL && strcmp(line, expected) == 0);
		}
		if (pass)
			printf("[%02d] \033[32mOK\033[0m\n", g_test);
		else
			printf("[%02d] \033[31mKO\033[0m (ret=%d, got='%s', expected='%s')\n",
				g_test, ret, line ? line : "(null)", expected);
	}
	free(line);
	g_test++;
}

int	main(void)
{
	int	fd;
	int	saved_stdin;

	signal(SIGSEGV, sigsegv_handler);

	title("Invalid fd: ");
	fd = open("files/empty", O_RDONLY);
	gnl(1000, NULL);
	gnl(-1, NULL);
	close(fd);
	gnl(fd, NULL);
	printf("\n");

	title("files/empty: ");
	fd = open("files/empty", O_RDONLY);
	gnl(fd, NULL);
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/nl: ");
	fd = open("files/nl", O_RDONLY);
	gnl(fd, "\n");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/41_no_nl: ");
	fd = open("files/41_no_nl", O_RDONLY);
	gnl(fd, "01234567890123456789012345678901234567890");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/41_with_nl: ");
	fd = open("files/41_with_nl", O_RDONLY);
	gnl(fd, "0123456789012345678901234567890123456789\n");
	gnl(fd, "0");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/42_no_nl: ");
	fd = open("files/42_no_nl", O_RDONLY);
	gnl(fd, "012345678901234567890123456789012345678901");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/42_with_nl: ");
	fd = open("files/42_with_nl", O_RDONLY);
	gnl(fd, "01234567890123456789012345678901234567890\n");
	gnl(fd, "1");
	gnl(fd, NULL);
	g_test = 1;
	printf("\n");
	close(fd);

	title("files/43_no_nl: ");
	fd = open("files/43_no_nl", O_RDONLY);
	gnl(fd, "0123456789012345678901234567890123456789012");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/43_with_nl: ");
	fd = open("files/43_with_nl", O_RDONLY);
	gnl(fd, "012345678901234567890123456789012345678901\n");
	gnl(fd, "2");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/multiple_nlx5: ");
	fd = open("files/multiple_nlx5", O_RDONLY);
	gnl(fd, "\n");
	gnl(fd, "\n");
	gnl(fd, "\n");
	gnl(fd, "\n");
	gnl(fd, "\n");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/multiple_line_no_nl: ");
	fd = open("files/multiple_line_no_nl", O_RDONLY);
	gnl(fd, "01234567890123456789012345678901234567890\n");
	gnl(fd, "987654321098765432109876543210987654321098\n");
	gnl(fd, "0123456789012345678901234567890123456789012\n");
	gnl(fd, "987654321098765432109876543210987654321098\n");
	gnl(fd, "01234567890123456789012345678901234567890");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/multiple_line_with_nl: ");
	fd = open("files/multiple_line_with_nl", O_RDONLY);
	gnl(fd, "9876543210987654321098765432109876543210\n");
	gnl(fd, "01234567890123456789012345678901234567890\n");
	gnl(fd, "987654321098765432109876543210987654321098\n");
	gnl(fd, "01234567890123456789012345678901234567890\n");
	gnl(fd, "9876543210987654321098765432109876543210\n");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/alternate_line_nl_no_nl: ");
	fd = open("files/alternate_line_nl_no_nl", O_RDONLY);
	gnl(fd, "98765432109876543210987654321098765432109\n");
	gnl(fd, "\n");
	gnl(fd, "012345678901234567890123456789012345678901\n");
	gnl(fd, "\n");
	gnl(fd, "9876543210987654321098765432109876543210987\n");
	gnl(fd, "\n");
	gnl(fd, "012345678901234567890123456789012345678901\n");
	gnl(fd, "\n");
	gnl(fd, "98765432109876543210987654321098765432109");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/alternate_line_nl_with_nl: ");
	fd = open("files/alternate_line_nl_with_nl", O_RDONLY);
	gnl(fd, "01234567890123456789012345678901234567890\n");
	gnl(fd, "\n");
	gnl(fd, "987654321098765432109876543210987654321090\n");
	gnl(fd, "\n");
	gnl(fd, "0123456789012345678901234567890123456789012\n");
	gnl(fd, "\n");
	gnl(fd, "987654321098765432109876543210987654321090\n");
	gnl(fd, "\n");
	gnl(fd, "01234567890123456789012345678901234567890\n");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/big_line_no_nl: ");
	fd = open("files/big_line_no_nl", O_RDONLY);
	gnl(fd, "");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("files/big_line_with_nl: ");
	fd = open("files/big_line_with_nl", O_RDONLY);
	gnl(fd, "\n");
	gnl(fd, NULL);
	printf("\n");
	close(fd);

	title("stdin: ");
	saved_stdin = dup(0);
	fd = open("files/alternate_line_nl_with_nl", O_RDONLY);
	dup2(fd, 0);
	close(fd);
	gnl(0, "01234567890123456789012345678901234567890\n");
	gnl(0, "\n");
	gnl(0, "987654321098765432109876543210987654321090\n");
	gnl(0, "\n");
	gnl(0, "0123456789012345678901234567890123456789012\n");
	gnl(0, "\n");
	gnl(0, "987654321098765432109876543210987654321090\n");
	gnl(0, "\n");
	gnl(0, "01234567890123456789012345678901234567890\n");
	gnl(0, NULL);
	dup2(saved_stdin, 0);
	close(saved_stdin);
	write(1, "\n", 1);
	return (0);
}
